const items = $input.all();
const results = [];
for (const item of items) {
  const subject = (item.json.subject || '').toLowerCase();
  const from = (item.json.from && item.json.from.emailAddress && item.json.from.emailAddress.address || item.json.from || '').toLowerCase();
  const bodyHtml = (item.json.body && item.json.body.content) || '';
  const bodyText = item.json.bodyPreview || '';
  const searchIn = bodyHtml || bodyText;
  const isAnthropicSender = from.includes('anthropic.com');
  const isLoginSubject = subject.includes('claude') || subject.includes('sign in') || subject.includes('secure link') || subject.includes('log in') || subject.includes('magic') || subject.includes('verify');
  if (!isAnthropicSender && !isLoginSubject) continue;
  let magicUrl = null;
  const patterns = [
    new RegExp('https://platform\\.claude\\.com/magic-link[^\\s"\' <>)\\\\]+', 'i'),
    new RegExp('https://claude\\.ai/magic-link[^\\s"\' <>)\\\\]+', 'i'),
    new RegExp('https://platform\\.claude\\.com/[^\\s"\' <>)\\\\]+', 'i'),
  ];
  for (const pattern of patterns) {
    const m = searchIn.match(pattern);
    if (m) { magicUrl = m[0].replace(/&amp;/g, '&').replace(/[.,;!?]+$/, ''); break; }
  }
  if (magicUrl) results.push({ json: { url: magicUrl, subject: item.json.subject, from: from, timestamp: new Date().toISOString() } });
}
return results.length ? results : [];
